import React from "react";
import styleContacts from "./Dialogues.module.scss";
import Users from "./users/Users";

const Dialogues = () => {
  const refreshTime = 2000;
  async function getListUsers() {
    const request = await fetch("http://localhost:5000/api/chat", {
      method: "GET",
      credentials: "include",
      headers: {
        //@ts-ignore
        Authentication: JSON.parse(localStorage.getItem("user")).accessToken,
      },
    });
    const response = await request.json();
    console.log(response);
  }

  React.useEffect(() => {
    const comInterval = setInterval(getListUsers, refreshTime); //This will refresh the data at regularIntervals of refreshTime
    return () => clearInterval(comInterval); //Clear interval on component unmount to avoid memory leak
  }, []);
  return (
    <div className={styleContacts.dialogs}>
      <p>DIALOGUES</p>
      <div className={styleContacts.users}>
        <Users />
      </div>
    </div>
  );
};

export default Dialogues;
